{
  "type": "DRAG_FILL",
  "lessonText": "Engage in a fun challenge to reinforce game development concepts.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks to complete the game loop.",
        "codeTemplate": "while ___: \n    ___ \n    ___",
        "options": ["running", "update_game()", "render_frame()"],
        "correctAnswer": "running,update_game(),render_frame()",
        "explanation": "The game loop continues while the game is running, updating the game state and rendering frames."
      },
      {
        "instruction": "Complete the function to initialize the game.",
        "codeTemplate": "def ___(): \n    ___ \n    ___",
        "options": ["initialize_game", "load_assets()", "set_up_display()"],
        "correctAnswer": "initialize_game,load_assets(),set_up_display()",
        "explanation": "The initialization function sets up the game by loading assets and configuring the display."
      },
      {
        "instruction": "Fill in the blanks for the event handling.",
        "codeTemplate": "if ___: \n    ___ \n    ___",
        "options": ["event.type == QUIT", "cleanup()", "exit_game()"],
        "correctAnswer": "event.type == QUIT,cleanup(),exit_game()",
        "explanation": "Event handling checks for quit events to clean up resources and exit the game."
      }
    ]
  }
}
